#include <assert.h>
#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <chrono>
#include <omp.h>

#define MAX_MASK_WIDTH 10
#define MAX_BLOCK_SIZE 1024

template<typename T>
T mask[MAX_MASK_WIDTH];

template<typename T>
void conv1d(const T *in, T *out, const int input_width, const int mask_width, const int block_size)
{
  int num_blocks = input_width / block_size;

  #pragma omp target parallel num_teams(num_blocks) thread_limit(block_size)
  {
    int i = omp_get_thread_num() + omp_get_team_num() * block_size;
    T s = 0;
    int start = i - mask_width / 2;
    for (int j = 0; j < mask_width; j++) {
      if (start + j >= 0 && start + j < input_width) {
        s += in[start + j] * mask<T>[j];
      }
    }
    #pragma omp target parallel
    {
      if (omp_get_thread_num() == 0) {
        out[i] = s;
      }
    }
  }
}

template<typename T>
void conv1d_tiled(const T *in, T *out, const int input_width, const int mask_width, const int block_size)
{
  int num_blocks = input_width / block_size;
  int n = mask_width / 2;
  size_t sm_bytes = (block_size + MAX_MASK_WIDTH - 1) * sizeof(T);

  #pragma omp target parallel num_teams(num_blocks) thread_limit(block_size)
  {
    T *tile = (T *)omp_alloc(sm_bytes, omp_get_default_allocator());
    int tid = omp_get_thread_num();
    int bid = omp_get_team_num();
    int i = tid + bid * block_size;

    int halo_left = (bid - 1) * block_size + tid;
    if (tid >= block_size - n) {
      tile[tid - (block_size - n)] = (halo_left < 0 || halo_left >= input_width) ? 0 : in[halo_left];
    }

    if (i < input_width) {
      tile[n + tid] = in[i];
    } else {
      tile[n + tid] = 0; 
    }

    int halo_right = (bid + 1) * block_size + tid;
    if (tid < n) {
      tile[tid + block_size + n] = (halo_right >= input_width || halo_right < 0) ? 0 : in[halo_right];
    }

    #pragma omp target parallel barrier
    {}

    T s = 0;
    if (i < input_width) {
      for (int j = 0; j < mask_width; j++) {
        s += tile[tid + j] * mask<T>[j];
      }
      out[i] = s;
    }

    omp_free(tile, omp_get_default_allocator());
  }
}

template<typename T>
void conv1d_tiled_caching(const T *in, T *out, const int input_width, const int mask_width, const int block_size)
{
  int num_blocks = input_width / block_size;
  size_t sm_bytes = block_size * sizeof(T);

  #pragma omp target parallel num_teams(num_blocks) thread_limit(block_size)
  {
    T *tile = (T *)omp_alloc(sm_bytes, omp_get_default_allocator());
    int tid = omp_get_thread_num();
    int bid = omp_get_team_num();
    int i = tid + bid * block_size;

    if (i < input_width) {
      tile[tid] = in[i];
    } else {
      tile[tid] = 0;
    }

    #pragma omp target parallel barrier
    {}

    int this_tile_start = bid * block_size;
    int next_tile_start = (bid + 1) * block_size;
    int start = i - (mask_width / 2);

    if (i < input_width) {
      T s = 0;
      for (int j = 0; j < mask_width; j++) {
        int in_index = start + j;
        if (in_index >= 0 && in_index < input_width) {
          if (in_index >= this_tile_start && in_index < next_tile_start) {
            s += tile[tid + j - (mask_width / 2)] * mask<T>[j];
          } else {
            s += in[in_index] * mask<T>[j];
          }
        }
      }
      out[i] = s;
    }

    omp_free(tile, omp_get_default_allocator());
  }
}

template <typename T>
void reference(const T *h_in,
               const T *d_out,
               const T *h_mask,
               const int input_width,
               const int mask_width)
{
  bool ok = true;
  for (int i = 0; i < input_width; i++) {
    T s = 0;
    int start = i - mask_width / 2;
    for (int j = 0; j < mask_width; j++) {
      if (start + j >= 0 && start + j < input_width) {
        s += h_in[start + j] * h_mask[j];
      }
    }
    if (fabs(s - d_out[i]) > 1e-3) {
      ok = false;
      break;
    }
  }
  printf("%s\n", ok ? "PASS" : "FAIL");
}

template <typename T>
void conv1D(const int input_width, const int mask_width, const int repeat)
{
  size_t size_bytes = input_width * sizeof(T);

  T *a, *b;
  a = (T *)malloc(size_bytes); 
  b = (T *)malloc(size_bytes); 

  T h_mask[MAX_MASK_WIDTH];

  for (int i = 0; i < MAX_MASK_WIDTH; i++) h_mask[i] = 1; 

  srand(123);
  for (int i = 0; i < input_width; i++) {
    a[i] = rand() % 256;
  }

  T *d_a, *d_b;
  d_a = (T *)omp_alloc(size_bytes, omp_get_default_allocator());
  d_b = (T *)omp_alloc(size_bytes, omp_get_default_allocator());

  #pragma omp target data use_device_addr(d_a, d_b)
  {
    #pragma omp target update from(a[0:input_width]) device_addr(d_a)
    for (int i = 0; i < MAX_MASK_WIDTH; i++) mask<T>[i] = h_mask[i];

    #pragma omp target barrier

    for (int bs = 64; bs <= MAX_BLOCK_SIZE; bs = bs * 2) {
      auto start = std::chrono::steady_clock::now();
      for (int i = 0; i < repeat; i++) {
        conv1d<T>(d_a, d_b, input_width, mask_width, bs);
      }
      #pragma omp target barrier
      auto end = std::chrono::steady_clock::now();
      auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
      printf("Average kernel execution time of conv1d kernel (block size %d): %f (us)\n",
             bs, (time * 1e-3f) / repeat);

      #pragma omp target update to(b[0:input_width]) device_addr(d_b)
      reference(a, b, h_mask, input_width, mask_width);
    }

    for (int bs = 64; bs <= MAX_BLOCK_SIZE; bs = bs * 2) {
      auto start = std::chrono::steady_clock::now();
      for (int i = 0; i < repeat; i++) {
        conv1d_tiled<T>(d_a, d_b, input_width, mask_width, bs);
      }
      #pragma omp target barrier
      auto end = std::chrono::steady_clock::now();
      auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
      printf("Average kernel execution time of conv1d-tiled kernel (block size %d): %f (us)\n",
             bs, (time * 1e-3f) / repeat);

      #pragma omp target update to(b[0:input_width]) device_addr(d_b)
      reference(a, b, h_mask, input_width, mask_width);
    }

    for (int bs = 64; bs <= MAX_BLOCK_SIZE; bs = bs * 2) {
      auto start = std::chrono::steady_clock::now();
      for (int i = 0; i < repeat; i++) {
        conv1d_tiled_caching<T>(d_a, d_b, input_width, mask_width, bs);
      }
      #pragma omp target barrier
      auto end = std::chrono::steady_clock::now();
      auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
      printf("Average kernel execution time of conv1d-tiled-caching kernel (block size %d): %f (us)\n",
             bs, (time * 1e-3f) / repeat);

      #pragma omp target update to(b[0:input_width]) device_addr(d_b)
      reference(a, b, h_mask, input_width, mask_width);
    }
  }

  free(a);
  free(b);
  omp_free(d_a, omp_get_default_allocator());
  omp_free(d_b, omp_get_default_allocator());
}

int main(int argc, char* argv[]) {
  if (argc != 3) {
    printf("Usage: %s <input_width> <repeat>\n", argv[0]);
    return 1;
  }

  int input_width = atoi(argv[1]);

  input_width = (input_width + MAX_BLOCK_SIZE - 1) / MAX_BLOCK_SIZE * MAX_BLOCK_SIZE;

  const int repeat = atoi(argv[2]);

  for (int mask_width = 3; mask_width < MAX_MASK_WIDTH; mask_width += 2) {
    printf("\n---------------------\n");
    printf("Mask width: %d\n", mask_width); 

    printf("1D convolution (FP64)\n");
    conv1D<double>(input_width, mask_width, repeat);

    printf("1D convolution (FP32)\n");
    conv1D<float>(input_width, mask_width, repeat);

    printf("1D convolution (INT16)\n");
    conv1D<int16_t>(input_width, mask_width, repeat);
  }

  return 0;
}
